import React from 'react';
import { FiPackage, FiTruck, FiBox, FiGlobe, FiBriefcase, FiZap, FiTarget } from 'react-icons/fi';

const ServiceCard = ({ icon, title, desc, color }) => (
  <div className="col-lg-3 col-md-4 col-sm-6 mb-4">
    <div className="card h-100 border-0 shadow text-center p-4 rounded-4" 
         style={{ 
           transition: '0.3s', 
           cursor: 'pointer', 
           backgroundColor: 'rgba(255, 255, 255, 0.9)', 
           backdropFilter: 'blur(5px)' 
         }}>
      <div className="mb-3 d-flex justify-content-center" style={{ fontSize: '3rem', color: color }}>
        {icon}
      </div>
      <h6 className="fw-bold text-dark text-uppercase mb-2">{title}</h6>
      <p className="text-muted small mb-3">{desc}</p>
      <button className="btn btn-sm rounded-pill px-4 mt-auto shadow-sm text-white" style={{ backgroundColor: color, border: 'none' }}>
        Book Now
      </button>
    </div>
  </div>
);

const Home = () => {
  return (
    <div className="container mt-5">
      <div className="text-center py-5">
        <h1 className="fw-bold text-white mb-2 display-4" style={{ textShadow: '2px 2px 10px rgba(0,0,0,0.5)' }}>
          Apni Manzil
        </h1>
        <h4 className="text-warning fw-bold">Reliable Logistics Aggregator Platform</h4>
      </div>

      <div className="row g-4 justify-content-center pb-5">
        <ServiceCard icon={<FiPackage />} title="Courier Services" desc="Fast Domestic & Express Delivery" color="#2ecc71" />
        <ServiceCard icon={<FiTruck />} title="Transport" desc="Heavy Haulage & Roadways" color="#f1c40f" />
        <ServiceCard icon={<FiBox />} title="Packers & Movers" desc="Easy Home & Office Shifting" color="#f39c12" />
        <ServiceCard icon={<FiGlobe />} title="International" desc="Global Freight & Shipping" color="#9b59b6" />
        <ServiceCard icon={<FiBriefcase />} title="Business MSME" desc="B2B Bulk Logistics Solutions" color="#3498db" />
        <ServiceCard icon={<FiTarget />} title="Live Tracking" desc="Track Your Shipments 24/7" color="#1abc9c" />
        <ServiceCard icon={<FiZap />} title="AI Logistics" desc="Smart AI-Powered Solutions" color="#e74c3c" />
      </div>
    </div>
  );
};

export default Home;
